Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWNotasNFCe-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&FilCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "F.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilCod EndIf
If not (&NfeDtaEms.IsEmpty() AND &NfeDtaEms_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Em.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &NfeDtaEms WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, " - ") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &NfeDtaEms_To EndIf
If not (&ModCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Documentos") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ModCod) EndIf
If not (&NfeNum.IsEmpty() AND &NfePedCod.IsEmpty() AND &NfeNumZero.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "NºNF") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeNum WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Pedido") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = &NfePedCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = '' do Case Case &NfeNumZero = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "TODAS NOTAS"
Case &NfeNumZero = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "SOMENTE COM Nº NOTA"
EndCase EndIf
If not (&NfeSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Sts.") If Not &NfeSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &NfeSts.EnumerationDescription() Endif EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'NFECLIRAZ' &NfeCliRaz1.FromString(&GridStateDynamicFilter.Value) If not &NfeCliRaz1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeCliRaz1) EndIf Case &DynamicFiltersSelector1 = !'NFELCTNOM' &NfeLctNom1.FromString(&GridStateDynamicFilter.Value) If not &NfeLctNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lancamento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeLctNom1) EndIf Case &DynamicFiltersSelector1 = !'NFECLICOD' &NfeCliCod1.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCliCod1 EndIf Case &DynamicFiltersSelector1 = !'NFEPROTER' &NfeProTer1.FromString(&GridStateDynamicFilter.Value) If not &NfeProTer1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &NfeProTer1.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &NfeProTer1.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector1 = !'NFECLICNPJ' &NfeCliCnpj1.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCnpj1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "CPF/CNPJ" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeCliCnpj1) EndIf Case &DynamicFiltersSelector1 = !'NFECOD' &NfeCod1.FromString(&GridStateDynamicFilter.Value) If not &NfeCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Seq." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCod1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'NFECLIRAZ' &NfeCliRaz2.FromString(&GridStateDynamicFilter.Value) If not &NfeCliRaz2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeCliRaz2) EndIf Case &DynamicFiltersSelector2 = !'NFELCTNOM' &NfeLctNom2.FromString(&GridStateDynamicFilter.Value) If not &NfeLctNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lancamento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeLctNom2) EndIf Case &DynamicFiltersSelector2 = !'NFECLICOD' &NfeCliCod2.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCliCod2 EndIf Case &DynamicFiltersSelector2 = !'NFEPROTER' &NfeProTer2.FromString(&GridStateDynamicFilter.Value) If not &NfeProTer2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &NfeProTer2.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &NfeProTer2.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector2 = !'NFECLICNPJ' &NfeCliCnpj2.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCnpj2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "CPF/CNPJ" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeCliCnpj2) EndIf Case &DynamicFiltersSelector2 = !'NFECOD' &NfeCod2.FromString(&GridStateDynamicFilter.Value) If not &NfeCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Seq." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCod2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'NFECLIRAZ' &NfeCliRaz3.FromString(&GridStateDynamicFilter.Value) If not &NfeCliRaz3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeCliRaz3) EndIf Case &DynamicFiltersSelector3 = !'NFELCTNOM' &NfeLctNom3.FromString(&GridStateDynamicFilter.Value) If not &NfeLctNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lancamento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeLctNom3) EndIf Case &DynamicFiltersSelector3 = !'NFECLICOD' &NfeCliCod3.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCliCod3 EndIf Case &DynamicFiltersSelector3 = !'NFEPROTER' &NfeProTer3.FromString(&GridStateDynamicFilter.Value) If not &NfeProTer3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &NfeProTer3.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &NfeProTer3.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector3 = !'NFECLICNPJ' &NfeCliCnpj3.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCnpj3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "CPF/CNPJ" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeCliCnpj3) EndIf Case &DynamicFiltersSelector3 = !'NFECOD' &NfeCod3.FromString(&GridStateDynamicFilter.Value) If not &NfeCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Seq." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCod3 EndIf EndCase If &GridState.DynamicFilters.Count >= 4 &DynamicFiltersEnabled4 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(4) &DynamicFiltersSelector4 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector4 = !'NFECLIRAZ' &NfeCliRaz4.FromString(&GridStateDynamicFilter.Value) If not &NfeCliRaz4.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeCliRaz4) EndIf Case &DynamicFiltersSelector4 = !'NFELCTNOM' &NfeLctNom4.FromString(&GridStateDynamicFilter.Value) If not &NfeLctNom4.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lancamento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeLctNom4) EndIf Case &DynamicFiltersSelector4 = !'NFECLICOD' &NfeCliCod4.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCod4.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCliCod4 EndIf Case &DynamicFiltersSelector4 = !'NFEPROTER' &NfeProTer4.FromString(&GridStateDynamicFilter.Value) If not &NfeProTer4.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &NfeProTer4.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &NfeProTer4.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector4 = !'NFECLICNPJ' &NfeCliCnpj4.FromString(&GridStateDynamicFilter.Value) If not &NfeCliCnpj4.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "CPF/CNPJ" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&NfeCliCnpj4) EndIf Case &DynamicFiltersSelector4 = !'NFECOD' &NfeCod4.FromString(&GridStateDynamicFilter.Value) If not &NfeCod4.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Seq." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &NfeCod4 EndIf EndCase EndIf EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&VisibleColumnCount = 0 If &Session.Get(!'WWNotasNFCeColumnsSelector') <> '' &ColumnsSelectorXML = &Session.Get(!'WWNotasNFCeColumnsSelector') &ColumnsSelector.FromXml(&ColumnsSelectorXML) Else Do 'InitializeColumnsSelector' EndIf
For &ColumnsSelector_Column in &ColumnsSelector.Columns If &ColumnsSelector_Column.IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = GetMessageText(iif(&ColumnsSelector_Column.DisplayName.IsEmpty(), &ColumnsSelector_Column.ColumnName, &ColumnsSelector_Column.DisplayName)) &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Color = 11 &VisibleColumnCount += 1 EndIf EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order NfeFilCod EmpCod FilCod (NfeCod) when &OrderedBy = 1 order FilCod when &OrderedBy = 2 AND &OrderedDsc = False order (FilCod) when &OrderedBy = 2 AND &OrderedDsc = True order NfeCod when &OrderedBy = 3 AND &OrderedDsc = False order (NfeCod) when &OrderedBy = 3 AND &OrderedDsc = True order NfeNum when &OrderedBy = 4 AND &OrderedDsc = False order (NfeNum) when &OrderedBy = 4 AND &OrderedDsc = True order NfePedCod when &OrderedBy = 5 AND &OrderedDsc = False order (NfePedCod) when &OrderedBy = 5 AND &OrderedDsc = True order NfeDtaEms when &OrderedBy = 6 AND &OrderedDsc = False order (NfeDtaEms) when &OrderedBy = 6 AND &OrderedDsc = True order NfeCliCod when &OrderedBy = 7 AND &OrderedDsc = False order (NfeCliCod) when &OrderedBy = 7 AND &OrderedDsc = True order NfeCliRaz when &OrderedBy = 8 AND &OrderedDsc = False order (NfeCliRaz) when &OrderedBy = 8 AND &OrderedDsc = True order NfeVlrTot when &OrderedBy = 9 AND &OrderedDsc = False order (NfeVlrTot) when &OrderedBy = 9 AND &OrderedDsc = True order NfeSts when &OrderedBy = 10 AND &OrderedDsc = False order (NfeSts) when &OrderedBy = 10 AND &OrderedDsc = True
using DSWWNotasNFCe(&FilCod, &NfeDtaEms, &NfeDtaEms_To, &ModCod, &NfeNum, &NfePedCod , &NfeNumZero, &NfeSts, &DynamicFiltersSelector1, &NfeCliRaz1, &NfeLctNom1, &NfeCliCod1 , &NfeProTer1, &NfeCliCnpj1, &NfeCod1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &NfeCliRaz2 , &NfeLctNom2, &NfeCliCod2, &NfeProTer2, &NfeCliCnpj2, &NfeCod2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &NfeCliRaz3, &NfeLctNom3, &NfeCliCod3, &NfeProTer3, &NfeCliCnpj3 , &NfeCod3, &DynamicFiltersEnabled4, &DynamicFiltersSelector4, &NfeCliRaz4, &NfeLctNom4, &NfeCliCod4 , &NfeProTer4, &NfeCliCnpj4, &NfeCod4)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &VisibleColumnCount = 0 If &ColumnsSelector.Columns.Item(1).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = FilCod &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(2).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = NfeCod &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(3).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = NfeNum &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(4).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = NfePedCod &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(5).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = NfeDtaEms &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(6).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = NfeCliCod &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(7).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(NfeCliRaz) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(8).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = NfeVlrTot &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(9).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = NfeSts.EnumerationDescription() &VisibleColumnCount += 1 EndIf
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'InitializeColumnsSelector'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ColumnsSelector = new WWPColumnsSelector() WWP_ColumnsSelector_Add(&ColumnsSelector, !"FilCod", '', !'Filial', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"NfeCod", '', !'Seq.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"NfeNum", '', !'Nº NF', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"NfePedCod", '', !'Pedido', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"NfeDtaEms", '', !'Emissão', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"NfeCliCod", '', !'#', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"NfeCliRaz", '', !'Nome', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"NfeVlrTot", '', !'Valor NF', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"NfeSts", '', !'Status', True, '')
&UserCustomValue = LoadColumnsSelectorState.Udp(!'WWNotasNFCeColumnsSelector') If not(&UserCustomValue.IsEmpty()) &ColumnsSelectorAux.FromXml(&UserCustomValue) WWP_ColumnSelector_UpdateColumns(&ColumnsSelectorAux, &ColumnsSelector) EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWNotasNFCeGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWNotasNFCeGridState")) Else &GridState.FromXml(&Session.Get(!"WWNotasNFCeGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEDTAEMS" &NfeDtaEms.FromString(&GridStateFilterValue.Value) &NfeDtaEms_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"MODCOD" &ModCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFENUM" &NfeNum.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEPEDCOD" &NfePedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFENUMZERO" &NfeNumZero.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFESTS" &NfeSts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
